);


insert into public.events
  (name, description, organizer_name, address, city, state, latitude, longitude,
   start_datetime, end_datetime, event_status, visibility_status, parking_info, admission_info)
select
  v.name,
  v.description,
  v.organizer_name,
  v.address,
  v.city,
  v.state,
  v.latitude,
  v.longitude,
  v.start_datetime::timestamptz,
  v.end_datetime::timestamptz,
  v.event_status,
  v.visibility_status,
  v.parking_info,
  v.admission_info
from (
  values
    (
    'Warren Park Farmers Market',
    'Community farmers market serving Warren Park, IN. Confirm hours and vendors with local organizers.',
    'Warren Park Market Association',
    null,
    'Warren Park',
    'IN',
